changeSet.sql:
CREATE TABLE purchase_credit_notes ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, number VARCHAR(30) NOT NULL, purchase_invoice_id UUID NOT NULL, party_id UUID NOT NULL, issue_date DATE NOT NULL, reason VARCHAR(500), amount NUMERIC(19,2) NOT NULL DEFAULT 0, subtotal NUMERIC(19,2) NOT NULL DEFAULT 0, tax_amount NUMERIC(19,2) NOT NULL DEFAULT 0, total NUMERIC(19,2) NOT NULL DEFAULT 0, status VARCHAR(20) NOT NULL DEFAULT 'DRAFT', applied_to_invoice_id UUID, currency VARCHAR(3) NOT NULL DEFAULT 'MRU', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0, CONSTRAINT uk_purchase_credit_notes_tenant_number UNIQUE (tenant_id, number) );
CREATE INDEX idx_purchase_credit_notes_invoice ON purchase_credit_notes(purchase_invoice_id);
CREATE TABLE purchase_credit_note_lines ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, purchase_credit_note_id UUID NOT NULL, line_number INT NOT NULL, purchase_invoice_line_id UUID, product_id UUID NOT NULL, uom_id UUID NOT NULL, quantity NUMERIC(19,6) NOT NULL, unit_cost NUMERIC(19,4) NOT NULL, tax_rate NUMERIC(5,4) NOT NULL DEFAULT 0, line_total NUMERIC(19,2) NOT NULL, returned_to_stock_qty NUMERIC(19,6) NOT NULL DEFAULT 0, snapshot_name VARCHAR(250), snapshot_sku VARCHAR(64), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0 );
CREATE INDEX idx_purchase_credit_note_lines_note ON purchase_credit_note_lines(purchase_credit_note_id); CREATE INDEX idx_purchase_credit_note_lines_inv_line ON purchase_credit_note_lines(purchase_invoice_line_id);

DO $$
DECLARE
    t text;
    tables text[] := ARRAY['purchase_credit_notes', 'purchase_credit_note_lines'];
BEGIN
    FOREACH t IN ARRAY tables LOOP
        EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY', t);
        EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY', t);

        EXECUTE format('DROP POLICY IF EXISTS tenant_isolation_select ON %I', t);
        EXECUTE format(
            'CREATE POLICY tenant_isolation_select ON %I
                FOR SELECT
                USING (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)',
            t);

        EXECUTE format('DROP POLICY IF EXISTS tenant_isolation_modify ON %I', t);
        EXECUTE format(
            'CREATE POLICY tenant_isolation_modify ON %I
                FOR ALL
                USING (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)
                WITH CHECK (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)',
            t);
    END LOOP;
END
$$;

DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'minierp_app') THEN
        GRANT ALL ON TABLE purchase_credit_notes, purchase_credit_note_lines TO minierp_app;
    END IF;
END $$;
